mapper.select:
SELECT plan_num, plan_qty, plan_status, plan_start, plan_end, emp_num, item_num, COUNT(*) OVER() AS total_count FROM ( SELECT plan_num, plan_qty, plan_status, plan_start, plan_end, emp_num, item_num FROM production_plan
AND plan_start >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND plan_end <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND facility_num = #{facility_num}
AND item_num = #{item_num}
AND TO_CHAR(plan_num) LIKE '%' || #{keyword} || '%'
ORDER BY plan_num DESC ) WHERE ROWNUM BETWEEN #{startRow} AND #{endRow}
